const d = $input.item.json;
const platform = (d.platform || '').toLowerCase();
const contentType = (d.contentType || '').toLowerCase();
const isVideo =
  (platform === 'instagram' && contentType.includes('reel')) ||
  (platform === 'youtube' && contentType.includes('video'));

const DIMS = {
  youtube:   { width: 1280, height: 720 },
  instagram: { width: 1080, height: 1080 },
  linkedin:  { width: 1200, height: 628 },
  twitter:   { width: 1200, height: 675 },
  email:     { width: 600,  height: 338 },
  seo:       { width: 1200, height: 630 },
};
const dims = DIMS[platform] || DIMS.seo;

let prompt = '';
if (platform === 'youtube') {
  prompt = `${d.thumbnailConcept || d.title}. Bold YouTube thumbnail style, high contrast, cinematic lighting, professional photography, 16:9 composition, attention-grabbing modern design. No rendered text in image.`;
} else if (platform === 'instagram' && isVideo) {
  prompt = `${d.visualDirection || d.body?.slice(0, 200) || d.title}. Smooth cinematic short video, lifestyle motion, natural fluid movement, high production quality, modern social video aesthetic, 9:16 vertical format.`;
} else if (platform === 'instagram') {
  prompt = `${d.visualDirection || ''}. ${d.body?.slice(0, 150) || ''}. Instagram editorial photography, lifestyle aesthetic, natural lighting, aspirational composition, warm color grading, square format.`;
} else if (platform === 'linkedin') {
  prompt = `${d.hook || d.title}. Professional ${d.postType || 'post'} visual for LinkedIn, corporate yet modern, clean minimal design, business context, neutral background, editorial photography style.`;
} else if (platform === 'twitter') {
  prompt = `${d.title}. ${d.body?.slice(0, 150) || ''}. Editorial news-style image, journalistic photography aesthetic, clean composition, high contrast, modern digital media style.`;
} else if (platform === 'email') {
  prompt = `${d.title}. Clean email marketing header for ${d.campaignType || 'campaign'}, professional lifestyle photography, wide letterbox composition, high-end aesthetic.`;
} else {
  prompt = `${d.targetKeyword || d.title}. ${d.title}. Editorial hero image for article, authoritative journalism photography style, clean wide composition, informational and trustworthy aesthetic.`;
}

const MODEL_IMAGE = 'fal-ai/flux-pro/v1.1-ultra';
const MODEL_VIDEO = 'fal-ai/kling-video/v1.6/pro/text-to-video';

return {
  ...d,
  prompt,
  isVideo,
  dims,
  model: isVideo ? MODEL_VIDEO : MODEL_IMAGE,
  falImageUrl: `https://fal.run/${MODEL_IMAGE}`,
  falVideoUrl: `https://fal.run/${MODEL_VIDEO}`,
  falVideoQueueBase: `https://queue.fal.run/${MODEL_VIDEO}/requests`,
};

const imageUrl = $input.item.json.images?.[0]?.url;
if (!imageUrl) throw new Error('FAL Flux returned no image URL. Response: ' + JSON.stringify($input.item.json));
const source = $('Build Prompt').item.json;
return { ...source, generatedUrl: imageUrl };

const d = $input.item.json;
const falKey = $env.FAL_KEY;
if (!falKey) throw new Error('FAL_KEY environment variable not set');

// Submit video job
const submitRes = await fetch(d.falVideoUrl, {
  method: 'POST',
  headers: {
    'Authorization': `Key ${falKey}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    prompt: d.prompt,
    duration: '5',
    aspect_ratio: '9:16',
    negative_prompt: 'blur, distortion, watermark, text overlay, low quality, pixelated',
  }),
});
if (!submitRes.ok) {
  const body = await submitRes.text();
  throw new Error(`FAL video submit failed [${submitRes.status}]: ${body}`);
}
const { request_id } = await submitRes.json();
if (!request_id) throw new Error('FAL did not return a request_id');

// Poll until complete (max 60 × 10s = 10 min)
const queueBase = d.falVideoQueueBase;
let videoUrl = null;
for (let i = 0; i < 60; i++) {
  await new Promise(r => setTimeout(r, 10000));
  const statusRes = await fetch(`${queueBase}/${request_id}/status`, {
    headers: { 'Authorization': `Key ${falKey}` },
  });
  if (!statusRes.ok) continue;
  const { status } = await statusRes.json();
  if (status === 'COMPLETED') {
    const resultRes = await fetch(`${queueBase}/${request_id}`, {
      headers: { 'Authorization': `Key ${falKey}` },
    });
    const result = await resultRes.json();
    videoUrl = result.video?.url;
    break;
  } else if (status === 'FAILED') {
    throw new Error(`Kling video generation FAILED for record ${d.recordId}`);
  }
}
if (!videoUrl) throw new Error(`FAL video timed out after 10 minutes for record ${d.recordId}`);

return { ...d, generatedUrl: videoUrl };

// Pull original webhook data out of the failed execution
const runData = $json.execution?.data?.resultData?.runData;
const webhookRuns = runData?.['Airtable Webhook'];
const originalPayload = webhookRuns?.[0]?.data?.main?.[0]?.[0]?.json || {};
const failedNode = $json.execution?.lastNodeExecuted || 'Unknown node';
const errorMsg = $json.error?.message || 'Unknown error';

return {
  recordId: originalPayload.recordId || null,
  table: originalPayload.table || null,
  errorMessage: `${failedNode}: ${errorMsg}`,
};
